#include <iostream>

class Counter {
private:
    int value;
public:
    Counter(int v = 0) : value(v) {}

    int getValue() const {
        return value;
    }

    Counter& operator++() {
        ++value;
        return *this;
    }

    Counter operator++(int) {
        Counter temp = *this;
        ++value;
        return temp;
    }
};

int main() {
    // For test case 1:
    Counter tc1_c(5); 
    std::cout << (++tc1_c).getValue() << std::endl; 
    std::cout << tc1_c.getValue() << std::endl;

    // For test case 2:
    Counter tc2_c(10); 
    std::cout << (tc2_c++).getValue() << std::endl; 
    std::cout << tc2_c.getValue() << std::endl;

    // For test case 3:
    Counter tc3_c(1); 
    ++(++tc3_c); 
    std::cout << tc3_c.getValue() << std::endl;

    // For test case 4:
    Counter tc4_c(20); 
    Counter tc4_d = ++tc4_c; 
    Counter tc4_e = tc4_d++; 
    std::cout << tc4_c.getValue() << std::endl; 
    std::cout << tc4_d.getValue() << std::endl; 
    std::cout << tc4_e.getValue() << std::endl;

    return 0;
}
